}

package org.apache.commons.math3.util.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.apache.commons.math3.util.FastMath;

public class StepDefs {

    private double x;
    private double y;
    private double result;
    private Exception exception;

    @Given("the FastMath library is used")
    public void the_fastmath_library_is_used() {
        // FastMath is available
    }

    @Given("a negative base x = {double}")
    public void a_negative_base_x(double base) {
        this.x = base;
    }

    @Given("a large odd integer exponent y = {double}")
    public void a_large_odd_integer_exponent_y(double exponent) {
        this.y = exponent;
    }

    @When("I calculate FastMath.pow(x, y)")
    public void i_calculate_fastmath_pow_x_y() {
        try {
            this.result = FastMath.pow(x, y);
            this.exception = null;
        } catch (Exception e) {
            this.exception = e;
            // Store the exception but don't throw it here
        }
    }

    @Then("the result should be {double}")
    public void the_result_should_be(double expected) {
        if (exception != null) {
            fail("Expected result " + expected + " but got exception: " + exception.getMessage());
        }
        assertEquals("Result should be " + expected, expected, result, 0.0);
    }

    @Then("the result should be equal to Math.pow(x, y)")
    public void the_result_should_be_equal_to_math_pow() {
        if (exception != null) {
            fail("Expected Math.pow result but got exception: " + exception.getMessage());
        }
        double expected = Math.pow(x, y);
        assertEquals("Result should match Math.pow result", expected, result, 0.0);
    }
}

